static void
complete_hand (card_hand *my_hand, const struct decided_cards *decided_cards,
	       card_deck *deck)
{
  int i;
  int end = decided_cards->my_card_count;
  for (i = 0; i < end; i++)
    {
      insert_into_hand (my_hand, decided_cards->my_cards[i]);
    }
